        const html = this.html();
        this.loadInnerText(html);
        this.content.style.display = "none";
        this.source.style.display = "block";
        this.source.focus();
        this.Utilities.restoreScroll(this.source, this.sourceScroll);
        this.disableButtons();
        if (this.findBar.style.display !== 'none') this._runSearch(this.findBar.querySelector('.rtb-find-input').value);
